// Gather all metrics and compare against previous day
const staticData = $getWorkflowStaticData('global');

// Get data from all upstream nodes
const dailyData = $('npm Daily Downloads').first().json;
const weeklyData = $('npm Weekly Downloads').first().json;
const githubData = $('GitHub Stats').first().json;
const registryData = $('npm Registry Info').first().json;

// Extract metrics
const daily = dailyData.downloads || 0;
const weekly = weeklyData.downloads || 0;
const stars = githubData.stargazers_count || 0;
const forks = githubData.forks_count || 0;
const openIssues = githubData.open_issues_count || 0;

// Get latest version from registry
let latestVersion = 'unknown';
let totalVersions = 0;
try {
  const distTags = registryData['dist-tags'] || {};
  latestVersion = distTags.latest || 'unknown';
  const versions = registryData.versions || {};
  totalVersions = Object.keys(versions).length;
} catch (e) {
  // Registry response format may vary
}

// Compare with previous metrics
const prev = staticData.previousMetrics || {};
const prevDaily = prev.daily || 0;
const prevStars = prev.stars || 0;
const prevForks = prev.forks || 0;

// Detect significant changes
const alerts = [];
if (prevDaily > 0) {
  const dailyChange = ((daily - prevDaily) / prevDaily) * 100;
  if (dailyChange > 50) {
    alerts.push(`SPIKE: Daily downloads up ${dailyChange.toFixed(0)}% (${prevDaily} -> ${daily})`);
  } else if (dailyChange < -50) {
    alerts.push(`DROP: Daily downloads down ${Math.abs(dailyChange).toFixed(0)}% (${prevDaily} -> ${daily})`);
  }
}
if (stars > prevStars) {
  alerts.push(`NEW STARS: +${stars - prevStars} (${prevStars} -> ${stars})`);
}
if (forks > prevForks) {
  alerts.push(`NEW FORKS: +${forks - prevForks} (${prevForks} -> ${forks})`);
}

// Store current metrics for next comparison
staticData.previousMetrics = { daily, weekly, stars, forks, openIssues, latestVersion };

// Build the digest message
const date = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

let message = `DAILY METRICS -- ${date}\n`;
message += `${'='.repeat(40)}\n\n`;
message += `npm downloads (yesterday): ${daily.toLocaleString()}\n`;
message += `npm downloads (this week): ${weekly.toLocaleString()}\n`;
message += `GitHub stars: ${stars.toLocaleString()}\n`;
message += `GitHub forks: ${forks.toLocaleString()}\n`;
message += `Open issues: ${openIssues}\n`;
message += `Latest version: ${latestVersion}\n`;
message += `Total versions published: ${totalVersions}\n`;

if (alerts.length > 0) {
  message += `\nALERTS:\n${alerts.map(a => `  ${a}`).join('\n')}\n`;
} else if (prevDaily > 0) {
  message += `\nNo significant changes from previous day.\n`;
} else {
  message += `\nFirst run -- comparisons will appear tomorrow.\n`;
}

return [{ json: { message } }];
